var LINERS=[
  {id:'corsa',name:'Corsa',tag:'Race-only precision. Exclusively for race and ultra-low-volume shells demanding maximum control.',w:2,p:5,vol:'Low',vols:['LV','Race','Race/LV'],issues:['control','heel'],ins:['low','medium'],ank:['low','medium'],cal:['low','medium'],feat:['Cork fill system','Race-specific construction','Maximum energy transfer','Precision narrow last'],why:"The Corsa is built exclusively for race and ultra-low-volume shells. The cork fill system locks your heel down and eliminates dead space for total power transfer. If you are in a race shell, this is your liner."},
  {id:'gft',name:'GFT',tag:'The precision all-rounder. Built for low-volume downhill, touring, and crossover shells.',w:3,p:4,vol:'Medium',vols:['MV','LV','MV-Wide'],issues:['heel','control'],ins:['low','medium','high'],ank:['low','medium','high'],cal:['low','medium'],feat:['Cork fill system','All-mountain performance','Balanced volume','Versatile fit'],why:"The GFT is the go-to ZipFit liner for low-volume downhill shells, touring boots, and crossover shells. The cork fill system delivers a precise custom fit that transforms energy transfer and heel hold whether you are carving on the resort or skinning into the backcountry."},
  {id:'espresso',name:'Espresso',tag:'Ultralight LV touring precision. Built for the lightest, most dedicated AT shells.',w:2,p:4,vol:'Low-Medium',vols:['LV','Race/LV'],issues:['heel','control'],ins:['low','medium'],ank:['low','medium'],cal:['low','medium'],feat:['Cork fill system','Ultralight touring construction','LV precision fit','Uphill and downhill performance'],why:"The Espresso is ZipFit's ultralight LV touring liner, built specifically for dedicated low-volume AT shells. The cork fill system delivers a locked-in, responsive fit that performs on the descent without weighing you down on the ascent."},
  {id:'gara_lv',name:'Gara LV',tag:'Warm performance for low-volume shells. For lean to average calves with lean/bony ankles who need warmth.',w:4,p:4,vol:'Low-Medium',vols:['LV','Race','Race/LV'],issues:['cold','heel','control'],ins:['low','medium'],ank:['low','medium'],cal:['low','medium'],feat:['Cork fill system','Enhanced insulation','Low-volume shell fit','Cold-weather performance'],why:"The Gara LV brings serious warmth to skiers in low-volume shells with lean to average calf volume. If cold feet have been holding you back, the Gara LV delivers cork precision and real insulation without compromising the locked-in fit you need for performance skiing."},
  {id:'gara_hv',name:'Gara HV',tag:'Warm performance for medium- to high-volume shells. For lean to average calves with fuller ankles who run cold.',w:4,p:4,vol:'Medium-High',vols:['HV','MV','MV-Wide'],issues:['cold','heel','control'],ins:['medium','high'],ank:['medium','high'],cal:['low','medium'],feat:['Cork fill system','Enhanced insulation','Higher-volume shell fit','Cold-weather performance'],why:"The Gara HV pairs ZipFit cork warmth with a higher-volume shell fit for skiers who run cold but have lean to average calf volume. You get the warmth you need on cold days without sacrificing the precise custom fit the cork system delivers."},
  {id:'freeride',name:'Freeride',tag:'The all-mountain comfort liner. Built for higher-volume shells and fuller lower legs.',w:4,p:3,vol:'Medium-High',vols:['HV','MV','MV-Wide'],issues:['cold','heel'],ins:['medium','high'],ank:['medium','high'],cal:['medium','high'],feat:['Cork fill system','Fuller calf fit','Higher-volume shell fit','Great for all levels'],why:"The Freeride is the go-to liner for skiers in higher-volume shells who have a fuller or muscular lower leg. The higher-volume construction accommodates larger calf volume that other liners can struggle with, while the cork fill system still delivers a custom fit. A great choice for skiers of any level who want a comfortable, custom fit in a higher-volume shell."},
  {id:'workhorse',name:'Workhorse',tag:'Maximum warmth for higher-volume shells. Built for experts who live in their boots.',w:5,p:4,vol:'High',vols:['HV','MV','MV-Wide'],issues:['cold','pain'],ins:['high'],ank:['high'],cal:['high'],feat:['Cork fill system','Maximum insulation','Expert-level performance','All-day warmth'],why:"The Workhorse is ZipFit's warmest US liner, built for expert skiers and boot industry professionals who spend their days on snow in higher-volume shells. Maximum insulation keeps you warm on the coldest days while the cork fill system ensures you never sacrifice performance for warmth."}
];
var FIT_PROBLEMS=[
  {v:'heel_lift',l:'Heel lift',d:'Your heel rises or shifts inside the boot when you flex forward or pressure the tongue — you can feel it lifting with each turn.',icon:'🦶',msg:'ZipFit liners address heel lift directly. The cork fill system molds to your exact heel geometry, eliminating the dead space that causes lift. Your bootfitter can also fine-tune the shell fit for a lasting solution.',link:'#heel-lift-solutions'},
  {v:'shin_bang',l:'Shin bang',d:'A sharp bruising pain on your shin that builds through the day, usually after hard or repeated flexion into the tongue of the boot.',icon:'🦵',msg:'Shin bang is usually caused by forward lean, buckle tension, or liner pack-out. A ZipFit liner reduces pack-out significantly, keeping your fit consistent. Your bootfitter can address forward lean and buckle setup.',link:'#shin-bang-solutions'},
  {v:'toe_bang',l:'Toe bang',d:'Your longest toe hits the front of the shell on steep terrain or when flexing hard — painful on long runs and descents.',icon:'💥',msg:'Toe bang is often a shell length or flex issue. A ZipFit liner helps by eliminating excess volume that lets the foot slide forward. Your bootfitter can evaluate shell length and forefoot fit.',link:'#toe-bang-solutions'},
  {v:'navicular_pain',l:'Navicular / instep pain',d:'Pressure or pain on the top of your foot or over the arch — usually from the boot tongue pressing on a high instep or prominent navicular bone.',icon:'↕️',msg:'Navicular and instep pain is almost always a volume mismatch — the shell is pressing directly on a high spot. A ZipFit liner redistributes pressure by molding around the navicular instead of pressing on it. For severe cases your bootfitter can also punch the shell directly over the bone.',link:'#navicular-pain-solutions'},
  {v:'cold_feet',l:'Cold feet',d:'Your feet go numb or painfully cold within an hour or two on the mountain, regardless of sock thickness or how tight you buckle.',icon:'🥶',msg:'Cold feet are often made worse by poor fit — a loose liner allows air circulation that chills your foot. ZipFit liners dramatically reduce this by sealing the foot with a custom cork mold. For extreme cold, your bootfitter can also discuss insulation options.',link:'#cold-feet-solutions'},
  {v:'wide_forefoot',l:'Wide forefoot pressure',d:'Pain, numbness, or a pinching sensation across the ball of your foot — often worse after an hour of skiing as your foot swells.',icon:'↔️',msg:'Forefoot pressure is typically a shell width issue rather than a liner issue. Your ZipFit liner will not add pressure here — in fact it reduces overall volume inconsistency. Your bootfitter can punch or grind the shell for lasting relief.',link:'#wide-forefoot-solutions'},
  {v:'ankle_bite',l:'Ankle bite',d:'Sharp pressure or bruising on one or both sides of your ankle — usually from a bony prominence pressing directly into the shell or cuff buckle.',icon:'🦴',msg:'Ankle bite is caused by bony prominences pressing against the shell or cuff. A ZipFit liner provides a custom cork interface that cushions these areas. Your bootfitter can also spot-punch the shell for direct relief.',link:'#ankle-bite-solutions'},
  {v:'none',l:'No major issues',d:'Your boots are generally comfortable and you ski without significant pain or distraction — you just want a better, more precise fit.',icon:'✓',msg:'Great — your ZipFit liner will build on that comfort by delivering a more precise, custom fit through the cork fill system. Expect better heel hold, improved energy transfer, and a fit that stays consistent all season.',link:null}
];

function svgFF(rx,col){return'<svg viewBox="0 0 80 68" fill="none"><ellipse cx="40" cy="48" rx="'+rx+'" ry="16" fill="rgba('+col+',.14)" stroke="rgba('+col+',.6)" stroke-width="1.5"/><ellipse cx="40" cy="20" rx="'+(rx-3)+'" ry="11" fill="rgba('+col+',.14)" stroke="rgba('+col+',.6)" stroke-width="1.5"/></svg>';}
function svgFF1(){return svgFF(10,'168,207,224');}function svgFF2(){return svgFF(15,'168,207,224');}function svgFF3(){return svgFF(21,'232,201,106');}function svgFF4(){return svgFF(28,'240,160,100');}
function svgArch(cy1,cy2,col){return'<svg viewBox="0 0 90 54" fill="none"><path d="M8 '+cy1+' Q24 '+cy2+' 48 '+(cy2-4)+' Q68 '+(cy2-8)+' 82 42" stroke="rgba('+col+',.55)" stroke-width="1.5" stroke-linecap="round"/><path d="M8 '+cy1+' Q10 '+(cy2-10)+' 18 '+(cy2-18)+' Q28 '+(cy2-28)+' 40 '+(cy2-30)+' Q55 '+(cy2-32)+' 66 '+(cy2-24)+' Q76 '+(cy2-16)+' 82 42Z" fill="rgba('+col+',.09)" stroke="rgba('+col+',.38)" stroke-width="1.3"/></svg>';}
function svgA1(){return svgArch(44,42,'168,207,224');}function svgA2(){return svgArch(44,32,'168,207,224');}function svgA3(){return svgArch(46,18,'232,201,106');}
function svgAnk(rx,ry,col){return'<svg viewBox="0 0 80 60" fill="none"><ellipse cx="40" cy="30" rx="'+rx+'" ry="'+ry+'" fill="rgba('+col+',.1)" stroke="rgba('+col+',.55)" stroke-width="1.5"/><line x1="'+(40-rx)+'" y1="30" x2="'+(40+rx)+'" y2="30" stroke="rgba('+col+',.18)" stroke-width="1" stroke-dasharray="3,2"/></svg>';}
function svgAnk1(){return svgAnk(11,18,'168,207,224');}function svgAnk2(){return svgAnk(16,20,'168,207,224');}function svgAnk3(){return svgAnk(22,23,'232,201,106');}
function svgCalf(d,col){return'<svg viewBox="0 0 80 60" fill="none"><path d="'+d+'" fill="rgba('+col+',.09)" stroke="rgba('+col+',.55)" stroke-width="1.5" stroke-linejoin="round"/></svg>';}
